JOIN access."user" u ON lower(u.email) = lower(seed.email)
ON CONFLICT (user_role_id) DO UPDATE SET
    user_id = EXCLUDED.user_id, app_role = EXCLUDED.app_role, agency_id = EXCLUDED.agency_id,
    granted_at = EXCLUDED.granted_at, budget_access = EXCLUDED.budget_access,
    adaptive_planning = EXCLUDED.adaptive_planning, performance_plan_access = EXCLUDED.performance_plan_access;
SELECT setval(
    pg_get_serial_sequence('access.user_role', 'user_role_id'),
    COALESCE((SELECT MAX("user_role_id") FROM access.user_role), 1),
    (SELECT COUNT(*) > 0 FROM access.user_role)
);

