JOIN access."user" u ON lower(u.email) = lower(seed.email)
WHERE NOT EXISTS (
    SELECT 1 FROM access.user_agency_access existing
    WHERE existing.user_id = u.user_id
      AND existing.agency_id = seed.agency_id
      AND COALESCE(existing.service_id, '') = COALESCE(seed.service_id, '')
)
ON CONFLICT DO NOTHING;
SELECT setval(
    pg_get_serial_sequence('access.user_agency_access', 'access_id'),
    COALESCE((SELECT MAX("access_id") FROM access.user_agency_access), 1),
    (SELECT COUNT(*) > 0 FROM access.user_agency_access)
);

